def read_json(path: Path) -> dict[str, Any]:
    if not path.exists():
        return {}
    with path.open("r", encoding="utf-8") as f:
        return json.load(f)


def summarize_checks(checks: list[dict[str, Any]]) -> dict[str, Any]:
    if not checks:
        return {"n_checks": 0}
    n_common = [float(row.get("n_common", 0) or 0) for row in checks]
    supported = [
        row for row in checks
        if str(row.get("status")) in {"supported", "positive_mixed"}
    ]
    return {
        "n_checks": len(checks),
        "supported_or_positive": len(supported),
        "min_pairs": int(min(n_common)) if n_common else 0,
        "median_pairs": float(np.median(n_common)) if n_common else 0.0,
        "max_pairs": int(max(n_common)) if n_common else 0,
    }


def write_report(path: Path, theorem_rows: list[dict[str, Any]], stats: dict[str, Any]) -> None:
    lines = [
        "# Freq-HRL Theory Diagnostics",
        "",
        "This artifact states the formal claims that are currently supported by code-level invariants and experiment diagnostics. It is a proof scaffold, not a substitute for a full paper appendix.",
        "",
        "## Statistical Coverage",
        "",
        f"- checks: {stats.get('n_checks', 0)}",
        f"- supported or positive-mixed: {stats.get('supported_or_positive', 0)}",
        f"- paired seed/source counts: min={stats.get('min_pairs', 0)}, median={stats.get('median_pairs', 0)}, max={stats.get('max_pairs', 0)}",
        "",
        "## Theorems",
        "",
    ]
    for theorem in theorem_rows:
        lines.extend([
            f"### {theorem['id']}: {theorem['title']}",
            "",
            f"Statement: {theorem['statement']}",
            "",
            "Assumptions:",
        ])
        for assumption in theorem["assumptions"]:
            lines.append(f"- {assumption}")
        lines.extend([
            "",
            f"Proof sketch: {theorem['proof']}",
            "",
            f"Diagnostics: {theorem['diagnostic']}",
            "",
        ])
    path.write_text("\n".join(lines), encoding="utf-8")


def run_theory_report(output_dir: Path, paper_diagnostics_path: Path) -> dict[str, Any]:
    output_dir.mkdir(parents=True, exist_ok=True)
    paper = read_json(paper_diagnostics_path)
    checks = paper.get("statistical_checks", []) if isinstance(paper, dict) else []
    stats = summarize_checks(checks)
    payload = {
        "theorems": THEOREMS,
        "statistical_coverage": stats,
        "paper_diagnostics_path": str(paper_diagnostics_path),
    }
    with (output_dir / "theory_claims.json").open("w", encoding="utf-8") as f:
        json.dump(payload, f, indent=2)
    write_report(output_dir / "theory_report.md", THEOREMS, stats)
    return payload


def main() -> None:
    parser = argparse.ArgumentParser()
    parser.add_argument(
        "--paper-diagnostics",
        type=Path,
        default=Path("transit_hrl/results/freq_hrl_paper_diagnostics/claim_matrix.json"),
    )
    parser.add_argument(
        "--output-dir",
        type=Path,
        default=Path("transit_hrl/results/freq_hrl_theory_diagnostics"),
    )
    args = parser.parse_args()
    payload = run_theory_report(args.output_dir, args.paper_diagnostics)
    coverage = payload["statistical_coverage"]
    print(f"wrote {args.output_dir}")
    print(
        "theory_report "
        f"theorems={len(payload['theorems'])} "
        f"checks={coverage.get('n_checks', 0)} "
        f"median_pairs={coverage.get('median_pairs', 0)}"
    )


if __name__ == "__main__":
    main()
